    public static partial class VanillaLevelExt
    {
        public static T? GetStageBehaviour<T>(this LevelEngine level) where T : StageBehaviour
        {
            if (level == null || level.StageDefinition == null)
                return null;
            return level.StageDefinition.GetBehaviour<T>();
        }

        #region 推车
        public static void RefreshCarts(this LevelEngine level)
        {
            var cartRef = level.GetCartReference();
            if (cartRef != null)
                level.SpawnCarts(cartRef, LevelPositions.CART_START_X, 20);
        }
        public static void SpawnCarts(this LevelEngine game, NamespaceID cartRef, float x, float xInterval)
        {
            var carts = game.GetEntities(EntityTypes.CART);
            for (int i = 0; i < game.GetMaxLaneCount(); i++)
            {
                if (carts.Any(c => c.GetLane() == i && c.State == VanillaCartStates.IDLE))
                    continue;
                game.Spawn(cartRef, new Vector3(x - i * xInterval, 0, game.GetEntityLaneZ(i)), null);
            }
        }
        #endregion

        #region 游戏结束检查
        public static void CheckGameOver(this LevelEngine level)
        {
            if (level.IsCleared) // 关卡通关后不能再死亡
                return;
            if (level.IsGodMode()) // 上帝模式
                return;
            var gameOverEnemy = level.FindFirstEntity(e => e.Position.x < LevelPositions.GetBorderX(false) && e.CanEntityEnterHouse());
            if (gameOverEnemy != null)
            {
                level.GameOver(GameOverTypes.ENEMY, gameOverEnemy, null);
            }
        }
        #endregion

        #region 通关检查
        public static void CheckClearUpdate(this LevelEngine level)
        {
            var lastEnemy = level.GetFirstAliveEnemy();
            if (lastEnemy != null)
            {
                level.SetLastEnemyPosition(lastEnemy.Position);
            }
            else if (level.HasNoAliveEnemy())
            {
                level.PostWaveFinished(level.CurrentWave);
                level.SetNoEnergy(true);
                if (!level.IsAllEnemiesCleared())
                {
                    level.SetAllEnemiesCleared(true);
                    var lastEnemyPosition = level.GetLastEnemyPosition();
                    Vector3 position;
                    if (lastEnemyPosition.x <= LevelPositions.GetBorderX(false))
                    {
                        var x = level.GetEnemySpawnX();
                        var z = level.GetEntityLaneZ(Mathf.CeilToInt(level.GetMaxLaneCount() * 0.5f));
                        var y = level.GetGroundY(x, z);
                        position = new Vector3(x, y, z);
                    }
                    else
                    {
                        position = lastEnemyPosition;
                    }
                    ClearPickup.Produce(level, position);
                }
            }
        }
        #endregion

        #region 范围伤害
        public static DamageOutput[] Explode(this LevelEngine level, Vector3 center, float radius, int faction, float amount, DamageEffectList effects, Entity source, Predicate<IEntityCollider>? filter = null)
        {
            return level.Explode(center, radius, faction, amount, effects, new EntitySourceReference(source), filter);
        }
        public static DamageOutput[] Explode(this LevelEngine level, Vector3 center, float radius, int faction, float amount, DamageEffectList effects, ILevelSourceReference? source, Predicate<IEntityCollider>? filter = null)
        {
            List<DamageOutput> damageOutputs = new List<DamageOutput>();
            var overlapParam = OverlapParams.Hostile(faction, EntityCollisionHelper.MASK_VULNERABLE);
            foreach (IEntityCollider entityCollider in level.OverlapSphere(center, radius, overlapParam))
            {
                if (filter != null && !filter(entityCollider))
                    continue;
                var damageOutput = entityCollider.TakeDamage(amount, effects, source);
                if (damageOutput != null)
                {
                    damageOutputs.Add(damageOutput);
                }
            }
            return damageOutputs.ToArray();
        }
        public static DamageOutput[] ExplodeAgainstFriendly(this LevelEngine level, Vector3 center, float radius, int faction, float amount, DamageEffectList effects, Entity source)
        {
            return level.ExplodeAgainstFriendly(center, radius, faction, amount, effects, new EntitySourceReference(source));
        }
        public static DamageOutput[] ExplodeAgainstFriendly(this LevelEngine level, Vector3 center, float radius, int faction, float amount, DamageEffectList effects, ILevelSourceReference source)
        {
            List<DamageOutput> damageOutputs = new List<DamageOutput>();
            var overlapParam = OverlapParams.Friendly(faction, EntityCollisionHelper.MASK_VULNERABLE);
            foreach (IEntityCollider entityCollider in level.OverlapSphere(center, radius, overlapParam))
            {
                var damageOutput = entityCollider.TakeDamage(amount, effects, source);
                if (damageOutput != null)
                {
                    damageOutputs.Add(damageOutput);
                }
            }
            return damageOutputs.ToArray();
        }

        public static DamageOutput[] SplashDamage(this LevelEngine level, IEntityCollider excludeCollider, Vector3 center, float radius, int faction, float amount, DamageEffectList effects, Entity source)
        {
            return level.SplashDamage(excludeCollider, center, radius, faction, amount, effects, new EntitySourceReference(source));
        }
        public static DamageOutput[] SplashDamage(this LevelEngine level, IEntityCollider excludeCollider, Vector3 center, float radius, int faction, float amount, DamageEffectList effects, ILevelSourceReference source)
        {
            List<DamageOutput> damageOutputs = new List<DamageOutput>();
            var overlapParam = OverlapParams.Hostile(faction, EntityCollisionHelper.MASK_VULNERABLE);
            foreach (IEntityCollider entityCollider in level.OverlapSphere(center, radius, overlapParam))
            {
                if (entityCollider == excludeCollider)
                    continue;
                var damageOutput = entityCollider.TakeDamage(amount, effects, source);
                if (damageOutput != null)
                {
                    damageOutputs.Add(damageOutput);
                }
            }
            return damageOutputs.ToArray();
        }
        public static void ClearExplosionCorpses(this IEnumerable<DamageOutput> damageOutputs)
        {
            // 清理尸体。
            foreach (var output in damageOutputs)
            {
                var ent = output.Entity;
                if (ent.Type == EntityTypes.ENEMY && ent.IsDead)
                {
                    ent.Remove();
                }
            }
        }
        #endregion

        #region 生成旗帜僵尸
        public static Entity? SpawnFlagZombie(this LevelEngine level)
        {
            var lane = level.GetRandomEnemySpawnLane();
            return level.SpawnFlagZombie(lane);
        }
        public static Entity? SpawnFlagZombie(this LevelEngine level, int lane)
        {
            var x = level.GetEnemySpawnX();
            var z = level.GetEntityLaneZ(lane);
            var y = level.GetGroundY(x, z);
            var pos = new Vector3(x, y, z);

            // 根据地图ID生成不同的摇旗怪物  
            NamespaceID flagEnemyID = VanillaEnemyID.flagZombie;
            var areaID = level.AreaID;

            if (areaID == VanillaAreaID.halloween)
            {
                flagEnemyID = VanillaEnemyID.FlagSkeleton;
            }
            else if (areaID == VanillaAreaID.castle)
            {
                flagEnemyID = VanillaEnemyID.NetherCourier;
            }
            else if (areaID == VanillaAreaID.mausoleum)
            {
                flagEnemyID = VanillaEnemyID.FlagbearerZombie;
            }
            else if (areaID == VanillaAreaID.ship)
            {
                flagEnemyID = VanillaEnemyID.JollyRogerZombie;
            }
            else if (areaID == VanillaAreaID.palace)
            {
                flagEnemyID = VanillaEnemyID.AncientGhost;
            }

            return level.Spawn(flagEnemyID, pos, null);
        }
        #endregion

        #region 打雷
        public static void Thunder(this LevelEngine level)
        {
            level.AddBuff<ThunderBuff>();
            foreach (var ghost in level.GetEntities())
            {
                foreach (var buff in ghost.GetBuffs<GhostBuff>())
                {
                    GhostBuff.Illuminate(buff);
                }
            }
            var model = level.GetAreaModelInterface();
            model?.TriggerAnimation("Thunder");
            level.PlaySound(VanillaSoundID.thunder);
        }
        #endregion

        #region 下雨
        public static void StartRain(this LevelEngine level)
        {
            level.Spawn(VanillaEffectID.rain, new Vector3(LevelPositions.LEVEL_WIDTH * 0.5f, 0, 0), null);
        }
        #endregion

        #region 一大波
        public static bool IsDuringHugeWave(this LevelEngine level)
        {
            var waveState = level.WaveState;
            if (waveState == VanillaLevelStates.STATE_HUGE_WAVE_APPROACHING)
                return true;
            if (level.IsHugeWave(level.CurrentWave))
            {
                if (waveState == VanillaLevelStates.STATE_STARTED)
                    return true;
                if (waveState == VanillaLevelStates.STATE_FINAL_WAVE)
                    return true;
            }
            return false;
        }
        #endregion

        #region 导电
        public static bool IsConductiveGrid(this LevelEngine level, int column, int lane)
        {
            var grid = level.GetGrid(column, lane);
            if (grid == null)
                return false;
            return grid.IsConductive();
        }
        public static bool IsConductiveAt(this LevelEngine level, float x, float z)
        {
            var column = level.GetColumn(x);
            var lane = level.GetLane(z);
            return level.IsConductiveGrid(column, lane);
        }
        public static void GetConnectedConductiveGrids(this LevelEngine level, Vector3 pos, int xExpand, int yExpand, HashSet<LawnGrid> results)
        {
            var column = level.GetColumn(pos.x);
            var lane = level.GetLane(pos.z);
            level.GetConnectedConductiveGrids(column, lane, xExpand, yExpand, results);
        }
        public static void GetConnectedConductiveGrids(this LevelEngine level, int column, int lane, int xExpand, int yExpand, HashSet<LawnGrid> results)
        {
            for (int xOff = -xExpand; xOff <= xExpand; xOff++)
            {
                for (int yOff = -yExpand; yOff <= yExpand; yOff++)
                {
                    var col = column + xOff;
                    var lan = lane + yOff;
                    var grid = level.GetGrid(col, lan);
                    if (grid == null)
                        continue;
                    if (grid.IsConductive())
                    {
                        results.Add(grid);
                    }
                }
            }
        }
        #endregion

        #region 手持物品
        public static NamespaceID? GetHeldSeedEntityID(this LevelEngine level)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return null;
            return data.GetSeedEntityID(level);
        }
        #endregion

        #region 制品解锁
        public static Entity? SpawnUnlockArtifactPickup(this LevelEngine level, NamespaceID areaID, NamespaceID unlockID, NamespaceID artifactID, Vector3 position, Entity? spawner)
        {
            if (level.AreaID == areaID && !Global.Saves.IsUnlocked(unlockID))
            {
                if (!level.EntityExists(e => e.IsEntityOf(VanillaPickupID.artifactPickup) && e.GetPickupContentID() == artifactID))
                {
                    return level.Spawn(VanillaPickupID.artifactPickup, position, spawner)?.Let(e =>
                    {
                        e.SetPickupContentID(artifactID);
                    });
                }
            }
            return null;
        }
        #endregion

        #region 随机池器械
        public static NamespaceID GetRandomContraptionFromPool(this LevelEngine level, RandomGenerator rng)
        {
            var pool = level.GetRandomContraptionPool();
            if (pool != null)
            {
                return pool.Random(rng);
            }
            return VanillaContraptionID.dispenser;
        }
        #endregion
    }
